from typing import List

def reorderList(data: str) -> str:
    values = list(map(int, data.split()))

    if not values:
        return ""

    n = len(values)
    reordered = []

    for i in range((n + 1) // 2):
        reordered.append(values[i])
        if i != n - 1 - i:
            reordered.append(values[n - 1 - i])

    return ' '.join(map(str, reordered))

