function reorderList(data) {
    if (!data || data.length === 0) return data;
    let values = [];
    for (let i = 0; i < data.length; i++) {
        values.push(data[i]);
    }
    let result = [];
    let left = 0;
    let right = values.length - 1;
    while (left <= right) {
        if (left === right) {
            result.push(values[left]);
        }
        else {
            result.push(values[left]);
            result.push(values[right]);
        }
        left++;
        right--;
    }
    return result;
}

