class ListNode {
    int val;
    ListNode next;
    ListNode(int x) {
        val = x;
    }
}
class Solution {
    public void reorderList(ListNode data) {
        if (data == null || data.next == null) return;
        List<ListNode> nodes = new ArrayList<>();
        ListNode current = data;
        while (current != null) {
            nodes.add(current);
            current = current.next;
        }
        int left = 0, right = nodes.size() - 1;
        ListNode dummy = new ListNode(0);
        ListNode tail = dummy;
        while (left <= right) {
            if (left == right) {
                tail.next = nodes.get(left);
                tail = tail.next;
            }
            else {
                tail.next = nodes.get(left);
                tail = tail.next;
                tail.next = nodes.get(right);
                tail = tail.next;
            }
            left++;
            right--;
        }
        tail.next = null;
        data = dummy.next;
    }
}

