#include <vector>
#include <string>
using namespace std;
struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {
    }
}
;
class Solution {
    public:
    void reorderList(ListNode* head) {
        if (!head || !head->next) return;
        vector<int> values;
        ListNode* current = head;
        while (current) {
            values.push_back(current->val);
            current = current->next;
        }
        int n = values.size();
        ListNode* newHead = new ListNode(0);
        ListNode* newCurrent = newHead;
        for (int i = 0; i < (n + 1) / 2; ++i) {
            newCurrent->next = new ListNode(values[i]);
            newCurrent = newCurrent->next;
            if (i != n - 1 - i) {
                newCurrent->next = new ListNode(values[n - 1 - i]);
                newCurrent = newCurrent->next;
            }
        }
        head->val = newHead->next->val;
        head->next = newHead->next->next;
        newCurrent = head->next;
        for (int i = 1; i < (n + 1) / 2; ++i) {
            newCurrent->val = newHead->next->next->val;
            newCurrent = newCurrent->next;
            newHead = newHead->next->next;
        }
        newCurrent->next = nullptr;
    }
}
