package main

type ListNode struct {
    Val  int
    Next *ListNode
}

func reorderList(head *ListNode) {
    if head == nil || head.Next == nil {
        return
    }

    var values []int
    for node := head; node != nil; node = node.Next {
        values = append(values, node.Val)
    }

    n := len(values)
    for i, j := 0, n-1; i < j; i++ {
        if i+1 == j {
            head.Val = values[i]
            head.Next = &ListNode{Val: values[j]}
            return
        }
        head.Val = values[i]
        head.Next = &ListNode{Val: values[j]}
        head = head.Next
        j--
    }

    if n%2 == 1 {
        head.Val = values[n/2]
    }
}

