function reorderList(data) {
    if (!data || data.length < 2) return;
    let slow = 0, fast = 0;
    while (fast < data.length && fast + 1 < data.length) {
        slow++;
        fast += 2;
    }
    let secondHalf = data.slice(slow);
    secondHalf.reverse();
    let result = [];
    for (let i = 0; i < slow; i++) {
        result.push(data[i]);
        if (i < secondHalf.length) {
            result.push(secondHalf[i]);
        }
    }
    for (let i = 0; i < result.length; i++) {
        data[i] = result[i];
    }
}

